calcFn:
var cpg = spoolPrice / spoolWeight;
    var baseCost = cpg * printWeight;
    var adjusted = baseCost * (1 + failRate / 100);
    var pps = Math.floor(spoolWeight / printWeight);
    document.getElementById('costPerGram').textContent = dollar(cpg).replace('$', '$') + '/g';
    document.getElementById('printCost').textContent = dollar(baseCost);
    document.getElementById('adjustedCost').textContent = dollar(adjusted);
    document.getElementById('printsPerSpool').textContent = fmt(pps, 0);

var sideLen = Math.pow(volume, 1/3) * 10;
    var heightMM = sideLen;
    var layers = Math.ceil(heightMM / layerHeight);
    var effectiveInfill = infillPct / 100;
    var shellPerimeter = sideLen * 4;
    var infillPerLayer = sideLen * sideLen * effectiveInfill / (0.4);
    var totalPathLength = layers * (shellPerimeter + infillPerLayer);
    var timeSeconds = totalPathLength / printSpeed;
    var timeMinutes = timeSeconds / 60;
    var hours = Math.floor(timeMinutes / 60);
    var mins = Math.round(timeMinutes % 60);
    var filGrams = volume * 1.24 * (0.3 + effectiveInfill * 0.7);
    document.getElementById('totalLayers').textContent = fmt(layers, 0);
    document.getElementById('estTime').textContent = hours + 'h ' + mins + 'm';
    document.getElementById('filamentUsed').textContent = fmt(filGrams, 1) + ' g';

var shellFraction = Math.min(0.95, wallThickness * 0.1);
    var infillFraction = (1 - shellFraction) * (infillPct / 100);
    var totalFillFraction = shellFraction + infillFraction;
    var weight = volume * density * totalFillFraction;
    var solidWeight = volume * density;
    var saved = ((1 - totalFillFraction) * 100);
    var strength = Math.round(totalFillFraction * 100);
    if (infillPct >= 80) strength = Math.min(98, strength);
    document.getElementById('totalWeight').textContent = fmt(weight, 1) + ' g';
    document.getElementById('materialSaved').textContent = fmt(saved, 1) + '%';
    document.getElementById('strengthRating').textContent = strength + '% of solid';

var flow = layerHeight * lineWidth * printSpeed;
    var maxFlow = 15;
    var maxSpd = maxFlow / (layerHeight * lineWidth);
    var filDia = 1.75;
    var filArea = Math.PI * Math.pow(filDia / 2, 2);
    var extRate = flow / filArea;
    document.getElementById('flowRate').textContent = fmt(flow, 2) + ' mm³/s';
    document.getElementById('maxSpeed').textContent = fmt(maxSpd, 0) + ' mm/s';
    document.getElementById('extrusionRate').textContent = fmt(extRate, 2) + ' mm/s';

var totalML = partVolume * (1 + supportPct / 100);
    var costPerML = bottlePrice / bottleVolume;
    var cost = totalML * costPerML;
    var ppb = Math.floor(bottleVolume / totalML);
    document.getElementById('totalResin').textContent = fmt(totalML, 1) + ' mL';
    document.getElementById('resinCost').textContent = dollar(cost);
    document.getElementById('partsPerBottle').textContent = fmt(ppb, 0);

var kwh = (wattage / 1000) * printHours;
    var costPrint = kwh * electricRate;
    var monthly = costPrint * printsPerMonth;
    document.getElementById('costPerPrint').textContent = dollar(costPrint);
    document.getElementById('monthlyCost').textContent = dollar(monthly);
    document.getElementById('kwhPerPrint').textContent = fmt(kwh, 2) + ' kWh';

var dia = parseFloat(diameter);
    var dens = parseFloat(density);
    var radiusCM = dia / 20;
    var areaCM2 = Math.PI * radiusCM * radiusCM;
    var volumeCM3 = weight / dens;
    var lengthCM = volumeCM3 / areaCM2;
    var meters = lengthCM / 100;
    var feet = meters * 3.28084;
    var cpm = 25 / meters;
    document.getElementById('lengthM').textContent = fmt(meters, 1) + ' m';
    document.getElementById('lengthFt').textContent = fmt(feet, 0) + ' ft';
    document.getElementById('costPerMeter').textContent = dollar(cpm) + '/m';

var usableX = bedX - 2 * margin;
    var usableY = bedY - 2 * margin;
    var area = usableX * usableY;
    var totalVol = bedX * bedY * bedZ / 1000;
    var usableVol = usableX * usableY * bedZ / 1000;
    document.getElementById('usableArea').textContent = fmt(area, 0) + ' mm² (' + fmt(usableX, 0) + '×' + fmt(usableY, 0) + ')';
    document.getElementById('buildVolume').textContent = fmt(totalVol, 0) + ' cm³';
    document.getElementById('usableVolume').textContent = fmt(usableVol, 0) + ' cm³';

var nCart = parseInt(numCartridges);
    var cpp = (cartridgePrice * nCart) / pageYield;
    var monthly = cpp * pagesPerMonth;
    var yearly = monthly * 12;
    var monthsPerSet = pageYield / pagesPerMonth;
    document.getElementById('costPerPage').textContent = '$' + (cpp).toFixed(3);
    document.getElementById('monthlyCost').textContent = dollar(monthly);
    document.getElementById('yearlyCost').textContent = dollar(yearly);
    document.getElementById('replacementFreq').textContent = fmt(monthsPerSet, 1) + ' months';

var gsm;
    if (fromUnit === 'gsm') gsm = weightValue;
    else if (fromUnit === 'bond') gsm = weightValue * 3.76;
    else if (fromUnit === 'cover') gsm = weightValue * 2.708;
    else if (fromUnit === 'index') gsm = weightValue * 1.81;
    var bond = gsm / 3.76;
    var cover = gsm / 2.708;
    var idx = gsm / 1.81;
    var mils = gsm * 0.06;
    document.getElementById('gsmResult').textContent = fmt(gsm, 1) + ' g/m²';
    document.getElementById('bondResult').textContent = fmt(bond, 1) + ' lb';
    document.getElementById('coverResult').textContent = fmt(cover, 1) + ' lb';
    document.getElementById('thicknessMils').textContent = fmt(mils, 1) + ' mils';

var bleedW = docWidth + 2 * bleed;
    var bleedH = docHeight + 2 * bleed;
    var safeW = docWidth - 2 * safeMargin;
    var safeH = docHeight - 2 * safeMargin;
    document.getElementById('bleedSize').textContent = fmt(bleedW, 3) + '" × ' + fmt(bleedH, 3) + '"';
    document.getElementById('safeZone').textContent = fmt(safeW, 3) + '" × ' + fmt(safeH, 3) + '"';
    document.getElementById('bleedSizeMM').textContent = fmt(bleedW * 25.4, 1) + ' × ' + fmt(bleedH * 25.4, 1) + ' mm';
    document.getElementById('safeZoneMM').textContent = fmt(safeW * 25.4, 1) + ' × ' + fmt(safeH * 25.4, 1) + ' mm';

var dpi = parseInt(targetDPI);
    var pw = pixelWidth / dpi;
    var ph = pixelHeight / dpi;
    var mp = (pixelWidth * pixelHeight) / 1000000;
    document.getElementById('printWidth').textContent = fmt(pw, 2) + '" (' + fmt(pw * 2.54, 1) + ' cm)';
    document.getElementById('printHeight').textContent = fmt(ph, 2) + '" (' + fmt(ph * 2.54, 1) + ' cm)';
    document.getElementById('megapixels').textContent = fmt(mp, 1) + ' MP';

var pps = parseInt(pagesPerSig);
    var roundedPages = Math.ceil(numPages / pps) * pps;
    var blanks = roundedPages - numPages;
    var sigs = roundedPages / pps;
    var sheetsPerSig = pps / 4;
    var totalSheets = sigs * sheetsPerSig;
    var cost = totalSheets * sheetCost;
    document.getElementById('totalSheets').textContent = fmt(totalSheets, 0) + ' sheets';
    document.getElementById('signatures').textContent = fmt(sigs, 0);
    document.getElementById('blankPages').textContent = fmt(blanks, 0) + ' blank pages';
    document.getElementById('sheetsCost').textContent = dollar(cost);

var w300 = imgWidth / 300;
    var h300 = imgHeight / 300;
    var w150 = imgWidth / 150;
    var h150 = imgHeight / 150;
    var recDPI = Math.max(72, Math.round(3438 / (viewDist * 12)));
    var wRec = imgWidth / recDPI;
    var hRec = imgHeight / recDPI;
    var sqft = (wRec * hRec) / 144;
    var cost = sqft * pricePerSqFt;
    document.getElementById('maxSize300').textContent = fmt(w300, 1) + '" × ' + fmt(h300, 1) + '"';
    document.getElementById('maxSize150').textContent = fmt(w150, 1) + '" × ' + fmt(h150, 1) + '"';
    document.getElementById('recommendedDPI').textContent = recDPI + ' DPI (at ' + viewDist + 'ft → ' + fmt(wRec, 1) + '" × ' + fmt(hRec, 1) + '")';
    document.getElementById('printCost').textContent = dollar(cost) + ' (' + fmt(sqft, 1) + ' sq ft)';

var sides = parseFloat(doubleSided);
    var fin = parseFloat(finish);
    var baseCost = (quantity / 100) * basePrice;
    var total = baseCost * sides * fin;
    var perCard = total / quantity;
    var per100 = total / (quantity / 100);
    document.getElementById('totalCost').textContent = dollar(total);
    document.getElementById('costPerCard').textContent = '$' + perCard.toFixed(3);
    document.getElementById('costPer100').textContent = dollar(per100);

var lps = parseInt(labelsPerSheet);
    var adjustedLabels = Math.ceil(totalLabels * (1 + wastePct / 100));
    var sheets = Math.ceil(adjustedLabels / lps);
    var totalAvailable = sheets * lps;
    var leftover = totalAvailable - totalLabels;
    var cost = sheets * sheetPrice;
    document.getElementById('sheetsNeeded').textContent = fmt(sheets, 0) + ' sheets';
    document.getElementById('totalLabelsOnSheets').textContent = fmt(totalAvailable, 0);
    document.getElementById('leftoverLabels').textContent = fmt(leftover, 0);
    document.getElementById('totalCost').textContent = dollar(cost);
